const t=JSON.parse('{"key":"v-73eae579","path":"/posts/%E6%B5%8B%E7%BB%98/%E5%9C%B0%E5%9B%BE%E6%8A%95%E5%BD%B1.html","title":"地图投影","lang":"en-US","frontmatter":{"description":"地图投影 地图投影详解 1. 概述 地图投影是将地球椭球体表面上的点、线、面投影到平面上的数学方法。由于地球是一个三维的椭球体，而地图是二维的平面，因此在进行地图投影时，必然会产生变形。地图投影的目标是尽可能减少变形，并根据不同的应用需求，保留特定的几何特性。 2. 投影分类 地图投影可以根据不同的标准进行分类，常见的分类方法包括： 按投影面分类: 圆柱投影: 将地球表面投影到圆柱面上，然后将圆柱面展开成平面。例如，墨卡托投影。 圆锥投影: 将地球表面投影到圆锥面上，然后将圆锥面展开成平面。例如，兰勃特等角圆锥投影。 方位投影: 将地球表面投影到与地球表面相切的平面上。例如，球心投影。 按投影性质分类: 等角投影: 保持投影前后角度不变，即投影后任意两条相交线段的夹角与投影前一致。例如，墨卡托投影。 等积投影: 保持投影前后面积不变，即投影后任意区域的面积与投影前一致。例如，阿尔伯斯等积投影。 等距投影: 保持投影前后特定方向上的距离不变。例如，等距方位投影。 任意投影: 不保持上述任何性质的投影，通常用于平衡各种变形。例如，罗宾逊投影。 按投影中心分类: 正轴投影: 投影面与地轴垂直。 横轴投影: 投影面与地轴平行。 斜轴投影: 投影面与地轴斜交。","head":[["meta",{"property":"og:url","content":"https://mister-hope.github.io/posts/%E6%B5%8B%E7%BB%98/%E5%9C%B0%E5%9B%BE%E6%8A%95%E5%BD%B1.html"}],["meta",{"property":"og:site_name","content":"入川为王"}],["meta",{"property":"og:title","content":"地图投影"}],["meta",{"property":"og:description","content":"地图投影 地图投影详解 1. 概述 地图投影是将地球椭球体表面上的点、线、面投影到平面上的数学方法。由于地球是一个三维的椭球体，而地图是二维的平面，因此在进行地图投影时，必然会产生变形。地图投影的目标是尽可能减少变形，并根据不同的应用需求，保留特定的几何特性。 2. 投影分类 地图投影可以根据不同的标准进行分类，常见的分类方法包括： 按投影面分类: 圆柱投影: 将地球表面投影到圆柱面上，然后将圆柱面展开成平面。例如，墨卡托投影。 圆锥投影: 将地球表面投影到圆锥面上，然后将圆锥面展开成平面。例如，兰勃特等角圆锥投影。 方位投影: 将地球表面投影到与地球表面相切的平面上。例如，球心投影。 按投影性质分类: 等角投影: 保持投影前后角度不变，即投影后任意两条相交线段的夹角与投影前一致。例如，墨卡托投影。 等积投影: 保持投影前后面积不变，即投影后任意区域的面积与投影前一致。例如，阿尔伯斯等积投影。 等距投影: 保持投影前后特定方向上的距离不变。例如，等距方位投影。 任意投影: 不保持上述任何性质的投影，通常用于平衡各种变形。例如，罗宾逊投影。 按投影中心分类: 正轴投影: 投影面与地轴垂直。 横轴投影: 投影面与地轴平行。 斜轴投影: 投影面与地轴斜交。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"en-US"}],["meta",{"property":"og:updated_time","content":"2025-08-16T04:37:55.000Z"}],["meta",{"property":"article:author","content":"入川为王"}],["meta",{"property":"article:modified_time","content":"2025-08-16T04:37:55.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"地图投影\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2025-08-16T04:37:55.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"入川为王\\",\\"url\\":\\"https://mister-hope.com\\"}]}"]]},"headers":[{"level":2,"title":"地图投影详解","slug":"地图投影详解","link":"#地图投影详解","children":[]}],"git":{"createdTime":1755319075000,"updatedTime":1755319075000,"contributors":[{"name":"TikTrack Developer","email":"user@example.com","commits":1}]},"readingTime":{"minutes":3.31,"words":993},"filePathRelative":"posts/测绘/地图投影.md","localizedDate":"August 16, 2025","excerpt":"<h1> 地图投影</h1>\\n<h2> 地图投影详解</h2>\\n<p><strong>1. 概述</strong></p>\\n<p>地图投影是将地球椭球体表面上的点、线、面投影到平面上的数学方法。由于地球是一个三维的椭球体，而地图是二维的平面，因此在进行地图投影时，必然会产生变形。地图投影的目标是尽可能减少变形，并根据不同的应用需求，保留特定的几何特性。</p>\\n<p><strong>2. 投影分类</strong></p>\\n<p>地图投影可以根据不同的标准进行分类，常见的分类方法包括：</p>\\n<ul>\\n<li><strong>按投影面分类:</strong>\\n<ul>\\n<li><strong>圆柱投影:</strong> 将地球表面投影到圆柱面上，然后将圆柱面展开成平面。例如，墨卡托投影。</li>\\n<li><strong>圆锥投影:</strong> 将地球表面投影到圆锥面上，然后将圆锥面展开成平面。例如，兰勃特等角圆锥投影。</li>\\n<li><strong>方位投影:</strong> 将地球表面投影到与地球表面相切的平面上。例如，球心投影。</li>\\n</ul>\\n</li>\\n<li><strong>按投影性质分类:</strong>\\n<ul>\\n<li><strong>等角投影:</strong> 保持投影前后角度不变，即投影后任意两条相交线段的夹角与投影前一致。例如，墨卡托投影。</li>\\n<li><strong>等积投影:</strong> 保持投影前后面积不变，即投影后任意区域的面积与投影前一致。例如，阿尔伯斯等积投影。</li>\\n<li><strong>等距投影:</strong> 保持投影前后特定方向上的距离不变。例如，等距方位投影。</li>\\n<li><strong>任意投影:</strong> 不保持上述任何性质的投影，通常用于平衡各种变形。例如，罗宾逊投影。</li>\\n</ul>\\n</li>\\n<li><strong>按投影中心分类:</strong>\\n<ul>\\n<li><strong>正轴投影:</strong> 投影面与地轴垂直。</li>\\n<li><strong>横轴投影:</strong> 投影面与地轴平行。</li>\\n<li><strong>斜轴投影:</strong> 投影面与地轴斜交。</li>\\n</ul>\\n</li>\\n</ul>","autoDesc":true}');export{t as data};
